-- Insert 28 new bodyweight strength exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Band-Resisted Squat', 'band-resisted-squat', 'Perform Band-Resisted Squat as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 8, NULL, 90, 40, 'Squat pattern using band tension to add ascending resistance and bracing demand. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: squat / knee / dominant / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Band-Resisted Squat as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Band-resisted squat strength', 'capacity', 'squat_knee_dominant_strength', 'band_resisted_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","spinal_erectors"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Band-Resisted Squat uses band tension to train squat pattern using band tension to add ascending resistance and bracing demand.","setup":["Inspect the band for wear and set a secure anchor or foot position before the athlete loads it.","Have the athlete stand on a long band or use a safe low anchor with band tension balanced through the hands or shoulders.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Band-Resisted Squat.","Sit into a controlled squat, keep knees tracking, then stand against increasing band tension.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Control the band; do not let it control you.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Knees track with toes.","Brace and breathe."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set.","Using a band that is too heavy or anchored at the wrong angle."]}'::jsonb),
  ('Bodyweight Box Squat', 'bodyweight-box-squat', 'Perform Bodyweight Box Squat as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 8, NULL, 90, 40, 'Controlled squat to a box that teaches depth consistency, tension, and force from a repeatable target. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: squat / knee / dominant / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Bodyweight Box Squat as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Box-supported squat strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_box_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Box Squat uses bodyweight leverage to train controlled squat to a box that teaches depth consistency, tension, and force from a repeatable target.","setup":["Use a stable box or bench that does not slide and matches the athlete''s current range.","Have the athlete stand in front of a stable box at a height that allows pain-free squat depth.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Bodyweight Box Squat.","Sit back and down to lightly touch the box, keep tension, then stand without rocking.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Knees track with toes.","Brace and breathe."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."]}'::jsonb),
  ('Bodyweight Lateral Lunge', 'bodyweight-lateral-lunge', 'Perform Bodyweight Lateral Lunge as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 6, NULL, 90, 30, 'Side-lunge pattern that builds frontal-plane leg strength and adductor capacity. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: squat / knee / dominant / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Bodyweight Lateral Lunge as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Frontal-plane leg strength', 'capacity', 'squat_knee_dominant_strength', 'bodyweight_lateral_lunge_strength', '{"primary_joint_actions":["hip_abduction_adduction_control","knee_flexion_extension","ankle_dorsiflexion","pelvis_control"],"primary_tissues":["adductors","quadriceps","glutes","hip_stabilizers"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"single_leg","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Lateral Lunge uses bodyweight leverage to train side-lunge pattern that builds frontal-plane leg strength and adductor capacity.","setup":["Have the athlete stand wide enough to shift into one hip without twisting the foot or pelvis.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Bodyweight Lateral Lunge.","Shift hips to one side, bend the working knee, keep the other leg long, and push back to center.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Knees track with toes.","Brace and breathe."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."]}'::jsonb),
  ('Assisted Single-Leg Squat to Box', 'assisted-single-leg-squat-to-box', 'Perform Assisted Single-Leg Squat to Box as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 5, NULL, 90, 30, 'Assisted single-leg squat pattern to a box that builds high-leverage leg strength with a safe target. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: squat / knee / dominant / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Assisted Single-Leg Squat to Box as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Single-leg squat progression', 'capacity', 'squat_knee_dominant_strength', 'assisted_single_leg_squat_to_box_strength', '{"primary_joint_actions":["single_leg_knee_flexion_extension","hip_control","ankle_stability","pelvis_control"],"primary_tissues":["quadriceps","glutes","adductors","foot_intrinsics"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"single_leg","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Assisted Single-Leg Squat to Box uses bodyweight leverage to train assisted single-leg squat pattern to a box that builds high-leverage leg strength with a safe target.","setup":["Use a stable box or bench that does not slide and matches the athlete''s current range.","Use a clear wall space and keep the area around the athlete free of traffic.","Have the athlete stand on one leg in front of a box and use a wall, post, or light fingertip support as needed.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Assisted Single-Leg Squat to Box.","Sit to the box with control, keep the knee tracking, then stand using the working leg.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Knees track with toes.","Brace and breathe."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."]}'::jsonb),
  ('Bodyweight Hip Hinge Good Morning', 'bodyweight-hip-hinge-good-morning', 'Perform Bodyweight Hip Hinge Good Morning as controlled resistance work. The athlete uses bodyweight leverage to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 10, NULL, 90, 50, 'Hip-hinge pattern that builds posterior-chain tension and teaches trunk control before heavier loading. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: hinge / posterior / chain / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Bodyweight Hip Hinge Good Morning as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Bodyweight hinge strength', 'capacity', 'hinge_posterior_chain_strength', 'bodyweight_hip_hinge_good_morning_strength', '{"primary_joint_actions":["hip_flexion_extension","trunk_bracing","neutral_spine_control"],"primary_tissues":["hamstrings","glutes","spinal_erectors"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Bodyweight Hip Hinge Good Morning uses bodyweight leverage to train hip-hinge pattern that builds posterior-chain tension and teaches trunk control before heavier loading.","setup":["Have the athlete stand tall with soft knees and hands across chest or behind head.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_steps":["Begin from the organized start position for Bodyweight Hip Hinge Good Morning.","Push hips back until hamstrings load, keep the spine organized, then squeeze glutes to stand.","Move with controlled tempo through the full range the athlete can own.","Reset posture and breath before the next repetition or side."],"coach_cues":["Own the start position.","Slow where it matters, strong through the finish.","Ribs over pelvis.","Final rep should look like the first.","Hips back, spine long.","Brace and breathe."],"common_faults":["Chasing more reps or resistance after alignment changes.","Rushing the eccentric or bouncing through the hard range.","Holding the breath for the entire set instead of bracing and breathing.","Changing stance, band path, or trunk position to survive the set."]}'::jsonb),
  ('Banded Good Morning', 'banded-good-morning', 'Perform Banded Good Morning as controlled resistance work. The athlete uses band tension to create a strength or control demand while keeping pain-free range, posture, and tempo repeatable.', 'BEGINNER', 8, 3, 8, NULL, 90, 40, 'Band-resisted hip hinge that builds posterior-chain strength with scalable tension. Use it when the goal is force production, tissue capacity, and repeatable positions with bands or body resistance rather than machines, free weights, or conditioning volume.', 'Primary subrole: hinge / posterior / chain / strength. Score Strength and body-control transfer honestly. Use band tension, leverage, tempo, range, and rest to keep Banded Good Morning as resistance work. Do not turn it into a rushed conditioning station or over-tag it as explosiveness simply because the athlete is working hard.', 'Set position first, control the hard range, then finish every rep like you could repeat it cleanly.', 'Band hinge strength', 'capacity', 'hinge_posterior_chain_strength', 'banded_good_morning_strength', '{"primary_joint_actions":["hip_flexion_extension","trunk_bracing","neutral_spine_control"],"primary_tissues":["hamstrings","glutes","spinal_erectors"],"primary_motor_control_demands":["alignment_control","tempo_control","bracing_under_resistance"],"postural_shape":"stacked_rib_pelvis","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Banded Good Morning uses band tension to train band-resisted hip hinge that builds posterior-chain strength with scalable tension.","setup":["Inspect the band for wear and set a secure anchor or foot position before the athlete loads it.","Have the athlete stand on a long band and place it safely across the upper back or shoulders.","Choose a range and resistance level the athlete can own without pain.","Set the brace before the first rep and rehearse the finish position."],"execution_ste