INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), COALESCE(m.role, 'primary'), m.slot, pos.order_index,
  COALESCE(m.freshness_required, FALSE), COALESCE(m.fatigue_sensitivity, 3), COALESCE(m.fatigue_cost, 3),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 0), COALESCE(m.intensity_ceiling, 'high')
FROM (VALUES
  ('band-resisted-squat', 'capacity', 'band_resisted_squat_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('bodyweight-box-squat', 'capacity', 'bodyweight_box_squat_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('bodyweight-lateral-lunge', 'capacity', 'bodyweight_lateral_lunge_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('assisted-single-leg-squat-to-box', 'capacity', 'assisted_single_leg_squat_to_box_strength', 'primary', 5, FALSE, 3, 3, 4, 0, 'high'),
  ('bodyweight-hip-hinge-good-morning', 'capacity', 'bodyweight_hip_hinge_good_morning_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('banded-good-morning', 'capacity', 'banded_good_morning_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('bodyweight-single-leg-rdl-reach', 'capacity', 'single_leg_rdl_reach_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('band-hip-thrust', 'capacity', 'band_hip_thrust_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('bodyweight-glute-bridge', 'capacity', 'bodyweight_glute_bridge_strength', 'primary', 5, FALSE, 3, 3, 1, 0, 'moderate'),
  ('banded-hamstring-curl', 'capacity', 'banded_hamstring_curl_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('banded-terminal-knee-extension', 'capacity', 'banded_terminal_knee_extension_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('band-chest-press', 'capacity', 'band_chest_press_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'high'),
  ('half-kneeling-band-overhead-press', 'capacity', 'half_kneeling_band_overhead_press_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('band-triceps-pressdown', 'capacity', 'band_triceps_pressdown_strength', 'primary', 5, FALSE, 3, 3, 1, 0, 'moderate'),
  ('band-row', 'capacity', 'band_row_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'high'),
  ('split-stance-band-row', 'capacity', 'split_stance_band_row_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('band-lat-pulldown', 'capacity', 'band_lat_pulldown_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'high'),
  ('band-face-pull', 'capacity', 'band_face_pull_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('band-pull-apart', 'capacity', 'band_pull_apart_strength', 'primary', 5, FALSE, 3, 3, 1, 0, 'moderate'),
  ('band-straight-arm-pulldown', 'capacity', 'band_straight_arm_pulldown_strength', 'primary', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('chin-up-isometric-hold', 'resilience', 'chin_up_isometric_hold_strength', 'primary', 5, FALSE, 2, 2, 3, 0, 'moderate'),
  ('active-dead-hang', 'resilience', 'active_dead_hang_strength', 'primary', 5, FALSE, 2, 2, 2, 0, 'moderate'),
  ('bear-crawl-hold', 'resilience', 'bear_crawl_hold_strength', 'primary', 5, FALSE, 2, 2, 2, 0, 'moderate'),
  ('band-pallof-press', 'resilience', 'band_pallof_press_strength', 'primary', 5, FALSE, 2, 2, 2, 0, 'moderate'),
  ('half-kneeling-pallof-press', 'resilience', 'half_kneeling_pallof_press_strength', 'primary', 5, FALSE, 2, 2, 3, 0, 'moderate'),
  ('band-anti-rotation-walkout', 'resilience', 'band_anti_rotation_walkout_strength', 'primary', 5, FALSE, 2, 2, 3, 0, 'moderate'),
  ('band-resisted-dead-bug-pullover', 'resilience', 'band_resisted_dead_bug_pullover_strength', 'primary', 5, FALSE, 2, 2, 3, 0, 'moderate'),
  ('tall-kneeling-band-chop', 'resilience', 'tall_kneeling_band_chop_strength', 'primary', 5, FALSE, 2, 2, 3, 0, 'moderate')
) AS m(slug, phase_key, slot, role, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

