  ('band-face-pull', 'reps', 3, 12, NULL, 90, NULL::integer, 60, 4, 6),
  ('band-pull-apart', 'reps', 3, 12, NULL, 90, NULL::integer, 60, 4, 6),
  ('band-straight-arm-pulldown', 'reps', 3, 10, NULL, 90, NULL::integer, 50, 5, 7),
  ('chin-up-isometric-hold', 'seconds', 3, NULL, 15, 60, NULL::integer, 15, 5, 7),
  ('active-dead-hang', 'seconds', 3, NULL, 20, 60, NULL::integer, 20, 4, 6),
