WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_dosage_profile d WHERE d.exercise_id = e.id AND d.profile_name = 'Default');

INSERT INTO coaching.exercise_safety_profile (
  exercise_id, risk_level, impact_level, requires_spotting, requires_coach_supervision,
  readiness_checks, contraindications, common_substitutions
)
SELECT e.id, COALESCE(m.risk_level, 2), COALESCE(m.impact_level, 0), COALESCE(m.requires_spotting, FALSE),
  COALESCE(m.requires_coach_supervision, 'recommended'),
  COALESCE(m.readiness_checks, ARRAY[]::text[]),
  COALESCE(m.contraindications, ARRAY[]::text[]),
  COALESCE(m.common_substitutions, ARRAY[]::text[])
FROM (VALUES
  ('band-resisted-squat', 2, 0, FALSE, 'recommended', ARRAY['Athlete can demonstrate the unloaded or easiest version without pain.', 'Athlete can brace and breathe without dizziness or excessive breath holding.', 'Athlete can stop the set before technique deteriorates.']::text[], ARRAY['Painful knee, hip, ankle, or back loading in the pattern.', 'Unsafe band anchor, damaged band, or uncontrolled recoil path.']::text[], ARRAY['Bodyweight box squat', 'Supported split squat', 'Band-resisted squat with lighter tension']::text[]),
  ('bodyweight-box-squat', 1, 0, FALSE, 'recommended', ARRAY['Athlete can demonstrate the unloaded or easiest version without pain.', 'Athlete can brace and breathe without dizziness or excessive breath holding.', 'Athlete can stop the set before technique deteriorates.']::text[], ARRAY['Painful knee, hip, ankle, or back loading in the pattern.']::text[], ARRAY['Bodyweight box squat', 'Supported split squat', 'Band-resisted squat with lighter tension']::text[]),
  ('bodyweight-lateral-lunge', 2, 0, FALSE, 'recommended', ARRAY['Athlete can demonstrate the unloaded or easiest version without pain.', 'Athlete can brace and breathe without dizziness or excessive breath holding.', 'Athlete can stop the set before technique deteriorates.']::text[], ARRAY['Painful knee, hip, ankle, or back loading in the pattern.']::text[], ARRAY['Bodyweight box squat', 'Supported split squat', 'Band-resisted squat with lighter tension']::text[]),
