INSERT INTO coaching.exercise_regimen_rule (
  exercise_id, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures,
  counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning
)
SELECT e.id,
  COALESCE(m.can_be_daily, FALSE),
  COALESCE(m.weekly_max_frequency, 3),
  COALESCE(m.minimum_hours_between_hard_exposures, 24),
  COALESCE(m.counts_as_high_intensity, FALSE),
  COALESCE(m.counts_as_high_impact, FALSE),
  COALESCE(m.counts_as_neural, TRUE),
  COALESCE(m.counts_as_tissue_stress, TRUE),
  COALESCE(m.counts_as_conditioning, FALSE)
FROM (VALUES
  ('band-resisted-squat', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('bodyweight-box-squat', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('bodyweight-lateral-lunge', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('assisted-single-leg-squat-to-box', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('bodyweight-hip-hinge-good-morning', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('banded-good-morning', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('bodyweight-single-leg-rdl-reach', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-hip-thrust', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('bodyweight-glute-bridge', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('banded-hamstring-curl', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('banded-terminal-knee-extension', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-chest-press', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('half-kneeling-band-overhead-press', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('band-triceps-pressdown', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-row', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('split-stance-band-row', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('band-lat-pulldown', FALSE, 3, 24, TRUE, FALSE, FALSE, TRUE, FALSE),
  ('band-face-pull', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-pull-apart', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-straight-arm-pulldown', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('chin-up-isometric-hold', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('active-dead-hang', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('bear-crawl-hold', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-pallof-press', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('half-kneeling-pallof-press', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-anti-rotation-walkout', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('band-resisted-dead-bug-pullover', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('tall-kneeling-band-chop', TRUE, 5, 12, FALSE, FALSE, FALSE, TRUE, FALSE)
) AS m(slug, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures, counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning)
JOIN coaching.exercise e ON e.slug = m.slug
WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_regimen_rule r WHERE r.exercise_id = e.id);

