-- Resistance band + body resistance cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'resistance_band_body_resistance_readiness',
  NULL,
  'Resistance band and body resistance without conditioning drift or wrong phase intent',
  'Band and body-resistance work must use leverage, tempo, tension, and full rest — not HIIT circuits, plyometric substitution, or Output-speed intent. Strength and body control are primary scores.',
  'Resistance band and body resistance cards span Capacity squat/hinge/push/pull strength and Resilience tissue-capacity, anti-movement, and joint-control patterns using bands, leverage, and minimal equipment.',
  'Low-equipment resistance builds force, tissue tolerance, and position ownership when dosed correctly. Poor placement, short rest, or mis-tagged explosiveness trains sloppy mechanics and steals from Output work.',
  'Place Capacity strength after Prepare & Access, Skill, and true Output when in the same session. Score Strength and body control honestly; keep Resilience work submaximal and tissue-focused. Do not program band/body circuits as Capacity strength substitutes.',
  'Do not chase reps, band tension, or speed after position quality drops. Do not program resistance work after conditioning or tag it as explosiveness when delivery is fatigued.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
